import{_ as l,o as a,c as i,aw as t}from"./chunks/framework.DLufY-ao.js";const u=JSON.parse('{"title":"Cline","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/common/ai/assistants/cline.md","filePath":"wiki/dev-commit/common/ai/assistants/cline.md"}'),o={name:"wiki/dev-commit/common/ai/assistants/cline.md"};function r(n,e,d,c,s,h){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="cline" tabindex="-1">Cline <a class="header-anchor" href="#cline" aria-label="Permalink to &quot;Cline&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><a href="https://github.com/cline/cline" target="_blank" rel="noreferrer">https://github.com/cline/cline</a> - GitHub</li><li><a href="https://docs.cline.bot/" target="_blank" rel="noreferrer">https://docs.cline.bot/</a> - Документация</li><li><a href="https://www.reddit.com/r/CLine/" target="_blank" rel="noreferrer">https://www.reddit.com/r/CLine/</a> - Reddit</li></ul></div><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><ul><li>Плагин для VSCode</li><li>Взаимодействие с OpenRouter (interface for LLMs) <a href="https://openrouter.ai/" target="_blank" rel="noreferrer">https://openrouter.ai/</a></li><li>Можно добавить ключи для LLM (добавлял OpenAI и Anthropic)</li><li>Почти нет документации, т.к понятный UI</li><li>Анализ изображений и снимков экрана браузера</li><li>Эмулирует результат в собственном браузере. Если загрузить изображение, то сравнивает его с тем что отрисовалось в браузере, если не соответствует, то перерисовывает</li></ul><h2 id="функционал" tabindex="-1">Функционал <a class="header-anchor" href="#функционал" aria-label="Permalink to &quot;Функционал&quot;">​</a></h2><h3 id="add-context" tabindex="-1">Add Context <a class="header-anchor" href="#add-context" aria-label="Permalink to &quot;Add Context&quot;">​</a></h3><ul><li><code>@url</code> - вставьте URL-адрес расширения для загрузки и преобразования в Markdown. Это полезно, когда вы хотите предоставить Cline последние документы.</li><li><code>@problems</code> - добавляет ошибки и предупреждения в рабочей области (панель &quot;Problems&quot;), которые Cline может исправить.</li><li><code>@file</code> - добавляет содержимое файла, чтобы вам не приходилось тратить время на запросы API для подтверждения чтения файла (+ ввод для поиска файлов).</li><li><code>@folder</code> - добавляет все файлы из папки одновременно для ускорения работы.</li><li><code>@terminal</code> - ссылка на содержимое Терминала</li><li><code>@git</code> - ссылка на “Working Changes” и “Commits”</li></ul><h3 id="фаил-clinerules" tabindex="-1"><strong>Файл .clinerules</strong> <a class="header-anchor" href="#фаил-clinerules" aria-label="Permalink to &quot;**Файл .clinerules**&quot;">​</a></h3><ul><li>Добавьте файл <em>.clinerules</em> в корневой уровень, чтобы указать пользовательские инструкции для проекта.</li></ul><h3 id="переключение-режима-plan-mode-и-act-mode" tabindex="-1">Переключение режима “Plan Mode” и “Act Mode” <a class="header-anchor" href="#переключение-режима-plan-mode-и-act-mode" aria-label="Permalink to &quot;Переключение режима “Plan Mode” и “Act Mode”&quot;">​</a></h3><h4 id="_1-plan-mode-режим-планирования" tabindex="-1">1. Plan Mode (Режим планирования) <a class="header-anchor" href="#_1-plan-mode-режим-планирования" aria-label="Permalink to &quot;1. Plan Mode (Режим планирования)&quot;">​</a></h4><ul><li>В этом режиме я помогаю спланировать решение задачи</li><li>Мы можем обсудить детали, требования и подход к реализации</li><li>Я могу задавать уточняющие вопросы и предлагать различные варианты решения</li><li>Этот режим полезен для сложных задач, требующих предварительного планирования</li></ul><h4 id="_2-act-mode-режим-деиствия" tabindex="-1">2. Act Mode (Режим действия) <a class="header-anchor" href="#_2-act-mode-режим-деиствия" aria-label="Permalink to &quot;2. Act Mode (Режим действия)&quot;">​</a></h4><ul><li>В этом режиме я непосредственно выполняю задачи</li><li>Могу писать код, создавать файлы, запускать команды</li><li>Работаю пошагово, подтверждая успешность каждого действия</li><li>Этот режим используется для реализации уже спланированного решения</li></ul><h3 id="диаграммы-mermaid" tabindex="-1">Диаграммы Mermaid <a class="header-anchor" href="#диаграммы-mermaid" aria-label="Permalink to &quot;Диаграммы Mermaid&quot;">​</a></h3><ul><li>Диаграммы Mermaid в режиме &quot;Plan mode&quot;</li><li>Cline может визуализировать свои планы с помощью блок-схем</li><li>Блок-схемы отображаются в чате</li></ul>',16)])])}const b=l(o,[["render",r]]);export{u as __pageData,b as default};
